// Inject logo
const LOGO = "data:image/png;base64,";
document.getElementById('nav-logo').src = LOGO;
document.getElementById('footer-logo').src = LOGO;

// Nav scroll
window.addEventListener('scroll', () => {
  const nav = document.getElementById('navbar');
  if(window.scrollY > 60){
    nav.classList.add('scrolled');
    // On scroll, make logo normal (not white) since nav is now white
    document.getElementById('nav-logo').style.filter = 'none';
    document.querySelector('.nav-tagline').style.color = '#6B7280';
    document.querySelector('.nav-divider').style.background = '#ddd';
  } else {
    nav.classList.remove('scrolled');
    // Hero is light — keep logo full color, dark text
    document.getElementById('nav-logo').style.filter = 'none';
    document.querySelector('.nav-tagline').style.color = 'rgba(13,31,68,0.55)';
    document.querySelector('.nav-divider').style.background = 'rgba(13,31,68,0.2)';
  }
});

// Mobile menu
function toggleMobile(){
  document.getElementById('mobile-menu').classList.toggle('open');
}
function closeMobile(){
  document.getElementById('mobile-menu').classList.remove('open');
}

// Scroll reveal
const obs = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if(e.isIntersecting){
      e.target.classList.add('up');
      obs.unobserve(e.target);
    }
  });
},{threshold:0.1});
document.querySelectorAll('.reveal').forEach(el => obs.observe(el));

// Hero reveal on load
window.addEventListener('load', () => {
  setTimeout(() => {
    document.querySelectorAll('.hero .reveal').forEach((el, i) => {
      setTimeout(() => el.classList.add('up'), i * 150);
    });
  }, 200);
});